// ❌ RUIM - Função complexa e confusa

const processUserData = (userData: any[], config: any) => {
  const result = userData
    .filter((item: any) => {
      if (config.filters && config.filters.length > 0) {
        return config.filters.some((filter: any) => {
          if (filter.type === 'string') {
            return item[filter.field] && 
                   item[filter.field].toLowerCase().includes(filter.value.toLowerCase());
          } else if (filter.type === 'number') {
            return item[filter.field] >= filter.value;
          } else if (filter.type === 'date') {
            return new Date(item[filter.field]) >= new Date(filter.value);
          }
          return false;
        });
      }
      return true;
    })
    .map((item: any) => {
      const transformed = {};
      if (config.fields) {
        config.fields.forEach((field: string) => {
          transformed[field] = item[field];
        });
      }
      return transformed;
    })
    .sort((a: any, b: any) => {
      if (config.sortBy) {
        const aVal = a[config.sortBy];
        const bVal = b[config.sortBy];
        return config.sortOrder === 'desc' ? bVal - aVal : aVal - bVal;
      }
      return 0;
    });

  return result;
};

