interface User {
  id: number;
  name: string;
  email: string;
  age: number;
  createdAt: Date;
}

// Funções pequenas e específicas
const filterByName = (users: User[], name: string): User[] => {
  return users.filter(user => 
    user.name.toLowerCase().includes(name.toLowerCase())
  );
};

const filterByAge = (users: User[], minAge: number): User[] => {
  return users.filter(user => user.age >= minAge);
};

const sortByName = (users: User[]): User[] => {
  return users.sort((a, b) => a.name.localeCompare(b.name));
};

// Função principal simples
const getUsersByName = (users: User[], name: string): User[] => {
  const filtered = filterByName(users, name);
  return sortByName(filtered);
};

