const totalTimeout = maxRetryAttempts + requestTimeout;

const calculateUserDiscount = (user: User, products: Product[]) => {
  const activeProducts = products.filter(product => product.status === 'active');
  const discountedProducts = activeProducts.map(product => ({
    id: product.id,
    name: product.name,
    finalPrice: product.price * 0.9 // 10% discount
  }));
  return discountedProducts;
};

const processActiveOrders = (orders: Order[]) => {
  const activeOrders = orders.filter(order => order.status === 'active');
  const processedOrders = activeOrders.map(order => ({
    ...order,
    processedAt: new Date()
  }));
  return processedOrders;
};
